     5→use std::fs::File;
     6→use std::io::Write;
     7→use std::path::PathBuf;
     8→use std::process::Command;
     9→use std::time::Instant;
    10→use std::{env, fmt};
    11→
    12→use phf_shared::{self, FmtConst};
    13→use serde_json::{self, Value};
    14→
    15→fn main() {
    16→    let start = Instant::now();
    17→
    18→    let style_out_dir = PathBuf::from(env::var_os("DEP_SERVO_STYLE_CRATE_OUT_DIR").unwrap());
    19→    let css_properties_json = style_out_dir.join("css-properties.json");
    20→    let out_dir = PathBuf::from(env::var_os("OUT_DIR").unwrap());
    21→
    22→    println!("cargo:out_dir={}", out_dir.display());
    23→
    24→    println!("cargo::rerun-if-changed=webidls");
    25→    println!("cargo::rerun-if-changed=codegen");
    26→    println!("cargo::rerun-if-changed={}", css_properties_json.display());
    27→    println!("cargo::rerun-if-changed=../../third_party/WebIDL/WebIDL.py");
    28→    // NB: We aren't handling changes in `third_party/ply` here.
    29→
    30→    let status = find_python()
    31→        .arg("codegen/run.py")
    32→        .arg(&css_properties_json)
    33→        .arg(&out_dir)
    34→        .status()
    35→        .unwrap();
    36→    if !status.success() {
    37→        std::process::exit(1)
    38→    }
    39→
    40→    println!("Binding generation completed in {:?}", start.elapsed());
    41→
    42→    let json = out_dir.join("InterfaceObjectMapData.json");
    43→    let json: Value = serde_json::from_reader(File::open(json).unwrap()).unwrap();
    44→    let mut map = phf_codegen::Map::new();
    45→    for (key, value) in json.as_object().unwrap() {
    46→        let parts = value.as_array().unwrap();
    47→        map.entry(
    48→            Bytes(key),
    49→            format!(
    50→                "Interface {{ define: {}, enabled: {} }}",
    51→                parts[0].as_str().unwrap(),
    52→                parts[1].as_str().unwrap()
    53→            ),
    54→        );
    55→    }
    56→    let phf = PathBuf::from(env::var_os("OUT_DIR").unwrap()).join("InterfaceObjectMapPhf.rs");
    57→    let mut phf = File::create(phf).unwrap();
    58→    writeln!(
    59→        &mut phf,
    60→        "pub(crate) static MAP: phf::Map<&'static [u8], Interface> = {};",
    61→        map.build(),
    62→    )
    63→    .unwrap();
    64→}
    65→
    66→#[derive(Eq, Hash, PartialEq)]
    67→struct Bytes<'a>(&'a str);
    68→
    69→impl FmtConst for Bytes<'_> {
    70→    fn fmt_const(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
    71→        write!(formatter, "b\"{}\"", self.0)
    72→    }
    73→}
    74→
    75→impl phf_shared::PhfHash for Bytes<'_> {
    76→    fn phf_hash<H: std::hash::Hasher>(&self, hasher: &mut H) {
    77→        self.0.as_bytes().phf_hash(hasher)
    78→    }
    79→}
    80→
    81→fn try_python_command(mut command: Command) -> Result<Command, String> {
    82→    let command_result = command.output();
    83→
    84→    if let Ok(output) = command_result {
    85→        return if output.status.success() {
    86→            Ok(command)
    87→        } else {
    88→            Err(format!(
    89→                "`{command:?}` failed with {}",
    90→                String::from_utf8_lossy(&output.stderr)
    91→            ))
    92→        };
    93→    }
    94→    Err(format!("`{command:?}` failed to run (is it installed?)"))
    95→}
    96→
    97→/// Tries to find a suitable python, which in Servo is always `uv run python`.
    98→///
    99→/// To be accommodating to different environments, which may manage python differently, we fallback
   100→/// to `python3` and `python` in that order.
   101→///
   102→/// Note: This function should be kept in sync with the version in `components/servo/build.rs`
   103→fn find_python() -> Command {
   104→    let mut command = Command::new("uv");
   105→    command.args(["run", "--frozen", "python"]);
   106→
   107→    let command_result = try_python_command(command).inspect_err(|e| println!("cargo:warning={e}"));
   108→    if let Ok(command) = command_result {
   109→        return command;
   110→    }
   111→
   112→    println!(
   113→        "cargo:warning=`uv` not found - Falling back to the default python! \
   114→        If the build fails, please install uv and make sure it is in your PATH or make sure \
   115→        to provision a python environment >= python 3.11."
   116→    );
   117→
   118→    let python3 = Command::new("python3");
   119→    let python3_result = try_python_command(python3);
   120→    if let Ok(command) = python3_result {
   121→        return command;
   122→    }
   123→
   124→    let python = Command::new("python");
   125→    let python_result = try_python_command(python);
   126→    if let Ok(command) = python_result {
   127→        return command;
   128→    }
   129→
   130→    // We first try `python` before printing an error for `python3`, since python3 is often missing
   131→    // provided via python on Windows (but not necessarily on linux).
   132→    println!("cargo:warning={}", python3_result.unwrap_err());
   133→    println!("cargo:warning={}", python_result.unwrap_err());
   134→
   135→    panic!("No suitable python found! Tried: `uv run python`, `python3`, `python`.");
   136→}
